fn find_path_in_maze(maze: Vec<Vec<i32>>, start: (usize, usize), end: (usize, usize)) -> Option<Vec<(usize, usize)>> {
    let mut queue = BinaryHeap::new();
    queue.push(Node::new(start.0, start.1, 0));
    let mut came_from = None;
    let mut cost_so_far = std::collections::BTreeMap::new();
    cost_so_far.insert((start.0, start.1), 0);

    while let Some(Node { x, y, cost, parent }) = queue.pop() {
        if (x, y) == end {
            let mut path = Vec::new();
            while let Some((x, y)) = parent {
                path.push((x, y));
                if let Some((x, y)) = came_from {
                    cost_so_far.remove(&(x, y));
                }
            }
            path.push(start);
            path.reverse();
            return Some(path);
        }

        for dx in -1..2 {
            for dy in -1..2 {
                let nx = x as i32 + dx;
                let ny = y as i32 + dy;
                if nx >= 0 && nx < maze.len() as i32 && ny >= 0 && ny < maze[0].len() as i32 {
                    if maze[nx as usize][ny as usize] == 0 && !cost_so_far.contains_key(&(nx as usize, ny as usize)) {
                        let new_cost = cost + 1;
                        cost_so_far.insert((nx as usize, ny as usize), new_cost);
                        queue.push(Node::new(nx as usize, ny as usize, new_cost));
                        came_from.insert((nx as usize, ny as usize), (x, y));
                    }
                }
            }
        }
    }

    None
}
