// Function to calculate the prime factorization of a number
void prime_factorization(int n, int* factors, int* powers) {
    for (int p = 2; p * p <= n; p++) {
        int power = 0;
        while (n % p == 0) {
            n /= p;
            power++;
        }
        if (power > 0) {
            factors[0] *= p;
            factors[1] += power;
        }
    }
    if (n > 1) {
        factors[0] *= n;
        factors[1]++;
    }
}

