int perfect_hash(char* tokens[], int len) {
    // Create a set of unique strings
    char* unique_tokens = (char*)malloc(len * sizeof(char));
    for (int i = 0; i < len; i++) {
        strcpy(unique_tokens + i * strlen(tokens[i]) + 1, tokens[i]);
    }
    int unique_len = strlen(unique_tokens);

    // Calculate the prime factorization of the unique string lengths
    int factors[2] = {0, 0};
    int powers[2] = {0, 0};
    prime_factorization(unique_len, factors, powers);

    // Create a perfect hash function
    int hash_value = factors[0];
    for (int i = 1; i < unique_len; i++) {
        hash_value += factors[0] * i;
    }

    // Return the perfect hash function
    free(unique_tokens);
    return hash_value;
}

