public class BloomFilter {
    private static final int DEFAULT_SIZE = 1000000;
    private static final int DEFAULT_HASH_FUNCTIONS = 5;

    private final boolean[] array;
    private final int[] hashFunctions;

    public BloomFilter(int size, int hashFunctions) {
        this.array = new boolean[size];
        this.hashFunctions = hashFunctions;
        this.resize(size, hashFunctions);
    }

    private void resize(int size, int hashFunctions) {
        this.array = new boolean[size];
        this.hashFunctions = hashFunctions;
    }

    public void add(String email) {
        for (int i = 0; i < hashFunctions; i++) {
            int index = hash(email, i) % array.length;
            array[index] = true;
        }
    }

    public boolean check(String email) {
        for (int i = 0; i < hashFunctions; i++) {
            int index = hash(email, i) % array.length;
            if (!array[index]) return false;
        }
        return true;
    }

    private int hash(String email, int index) {
        int hash = 0;
        for (char c : email.toCharArray()) {
            hash += c;
        }
        return hash + index;
    }
}

class Main {
    public static boolean checkEmailMembership(String email, BloomFilter bloomFilter) {
        return bloomFilter.check(email);
    }

