use std::collections::BinaryHeap;

struct FibonacciHeap<T: Ord + Clone> {
    heap: BinaryHeap<T>,
    count: usize,
}

impl<T: Ord + Clone> FibonacciHeap<T> {
    fn new() -> Self {
        FibonacciHeap {
            heap: BinaryHeap::new(),
            count: 0,
        }
    }

    fn insert(&mut self, value: T) {
        self.heap.push(value);
        self.count += 1;
    }

    fn extract_min(&mut self) -> Option<T> {
        if self.heap.is_empty() {
            return None;
        }
        let min = self.heap.pop().cloned();
        self.count -= 1;
        self.merge(min)
    }

    fn merge(&mut self, min: T) -> Option<T> {
        if self.heap.is_empty() {
            self.heap.push(min);
            self.count += 1;
            Some(min)
        } else {
            self.heap.push(min);
            self.count += 1;
            self.sift_up(min);
            Some(min)
        }
    }

    fn sift_up(&mut self, value: T) {
        let mut parent = self.heap.len() / 2 - 1;
        while parent > 0 && self.heap.peek().unwrap().cmp(&value) > 0 {
            self.heap.swap(0, parent);
            parent = (parent - 1) / 2;
        }
    }
}

fn minimize_distance(values: Vec<i32>) -> i32 {
    if values.is_empty() {
        return 0;
    }

    let mut heap = FibonacciHeap::new();
    for value in values {
        heap.insert(value);
    }

    let mut prev_value = *heap.extract_min().unwrap();
    let mut min_distance = 0;
    while let Some(value) = heap.extract_min() {
        min_distance = min_distance.max(value - prev_value);
        prev_value = value;
    }

    min_distance
}

fn main() {
    let values = vec![5, 3, 8, 1, 9];
    println!("{}", minimize_distance(values));
}
