function findCentroids(dataPoints, k) {
    let centroids = [];
    let centroidsMap = new Map();

    for (let i = 0; i < k; i++) {
        centroids.push(dataPoints[Math.floor(Math.random() * dataPoints.length)]);
        centroidsMap.set(centroids[i], i);
    }

    while (true) {
        let newCentroids = new Array(k).fill(null);
        let countMap = new Map();

        for (let point of dataPoints) {
            let closestCentroidIndex = findClosestCentroidIndex(point, centroids);
            if (!countMap.has(closestCentroidIndex)) {
                countMap.set(closestCentroidIndex, 0);
            }
            countMap.set(closestCentroidIndex, countMap.get(closestCentroidIndex) + 1);
            newCentroids[centroidsMap.get(closestCentroidIndex)] = updateCentroid(newCentroids[centroidsMap.get(closestCentroidIndex)], point, countMap);
        }

        if (areCentroidsEqual(centroids, newCentroids)) {
            break;
        }

        centroids = newCentroids;
    }

    return centroids;
}

function findClosestCentroidIndex(point, centroids) {
    let minDistance = Infinity;
    let closestCentroidIndex = -1;

    for (let i = 0; i < centroids.length; i++) {
        let distance = calculateDistance(point, centroids[i]);
        if (distance < minDistance) {
            minDistance = distance;
            closestCentroidIndex = i;
        }
    }

    return closestCentroidIndex;
}

function updateCentroid(centroid, point, countMap) {
    let sumX = centroid[0] * countMap.get(0) + point[0];
    let sumY = centroid[1] * countMap.get(0) + point[1];
    let count = countMap.get(0) + 1;
    return [sumX / count, sumY / count];
}

function calculateDistance(point1, point2) {
    return Math.sqrt(Math.pow(point1[0] - point2[0], 2) + Math.pow(point1[1] - point2[1], 2));
}

function areCentroidsEqual(centroids1, centroids2) {
    for (let i = 0; i < centroids1.length; i++) {
        if (centroids1[i][0] !== centroids2[i][0] || centroids1[i][1] !== centroids2[i][1]) {
            return false;
        }
    }
    return true;
}
