struct SkipListNode {
    int value;
    int* next[1 << __lg(10) + 1]; // Maximum number of levels in the skip list
    SkipListNode* head;
};

// Function to create a new node in the skip list
SkipListNode* newNode(int value) {
    SkipListNode* node = new SkipListNode;
    node->value = value;
    node->head = node;
    for (int i = 1; i <= (1 << __lg(10) + 1); i++) {
        node->next[i] = nullptr;
    }
    return node;
}

// Function to insert a value into the skip list
void insert(SkipListNode** head, int value) {
    SkipListNode* node = newNode(value);
    int level = 1;
    while (rand() % 2 && level <= (1 << __lg(10) + 1)) {
        level++;
    }
    node->next[level] = head[level - 1];
    head[level - 1] = node;
}

// Function to check if a value is present in the skip list
bool skip_list_contains(SkipListNode** head, int target) {
    if (*head == nullptr) {
        return false;
    }
    SkipListNode* node = *head;
    for (int i = (1 << __lg(10) + 1); i > 0; i--) {
        while (node->next[i] != nullptr && node->next[i]->value < target) {
            node = node->next[i];
        }
    }
    return node->value == target;
}

