use std::collections::VecDeque;

pub fn find_all_scc(graph: &Vec<Vec<usize>>) -> Vec<Vec<usize>> {
    let n = graph.len();
    let mut low = vec![n; n];
    let mut stack = Vec::new();
    let mut index = vec![0; n];
    let mut visited = vec![false; n];
    let mut sccs = Vec::new();

    fn dfs(node: usize, low: &mut Vec<usize>, stack: &mut Vec<usize>, index: &mut Vec<usize>, visited: &mut Vec<bool>, graph: &Vec<Vec<usize>>, sccs: &mut Vec<Vec<usize>>) {
        stack.push(node);
        index[node] = index.len();
        low[node] = index.len();
        visited[node] = true;

        for &neighbor in graph[node].iter() {
            if visited[neighbor] {
                low[node] = low[neighbor].min(low[node]);
            } else {
                dfs(neighbor, low, stack, index, visited, graph, sccs);
                low[node] = low[node].min(index[neighbor]);
            }
        }

        if low[node] == index[node] {
            let mut scc = Vec::new();
            while let Some(node) = stack.pop() {
                scc.push(node);
                visited[node] = false;
            }
            sccs.push(scc);
        }
    }

    for node in 0..n {
        if !visited[node] {
            dfs(node, &mut low, &mut stack, &mut index, &mut visited, graph, &mut sccs);
        }
    }

    sccs
}
