    Node* node = (Node*)malloc(sizeof(Node));
    node->interval = interval;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// Function to insert a new interval into the interval tree
Node* interval_insert(Node* root, Interval interval) {
    if (root == NULL) {
        return newNode(interval);
    }

    if (interval.start < root->interval.start) {
        root->left = interval_insert(root->left, interval);
    } else if (interval.end > root->interval.end) {
        root->right = interval_insert(root->right, interval);
    } else {
        // Handle overlap by merging intervals
        root->interval.end = (root->interval.end > interval.end) ? root->interval.end : interval.end;
    }

    return root;
}
