    Graph* graph = (Graph*)malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->adjList = (int**)malloc(numVertices * sizeof(int*));
    for (int i = 0; i < numVertices; i++) {
        graph->adjList[i] = (int*)malloc(numVertices * sizeof(int));
        for (int j = 0; j < numVertices; j++) {
            graph->adjList[i][j] = INT_MAX;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int source, int destination, int weight) {
    graph->adjList[source][destination] = weight;
}

// Function to implement Dijkstra's algorithm
void dijkstra(Graph* graph, int source) {
    int* distance = (int*)malloc(graph->numVertices * sizeof(int));
    int* visited = (int*)malloc(graph->numVertices * sizeof(int));
    PriorityQueueNode* priorityQueue = (PriorityQueueNode*)malloc(graph->numVertices * sizeof(PriorityQueueNode));

    // Initialize distances and visited arrays
    for (int i = 0; i < graph->numVertices; i++) {
        distance[i] = INT_MAX;
        visited[i] = 0;
    }
    distance[source] = 0;

    // Add source node to priority queue
    priorityQueue[0].vertex = source;
    priorityQueue[0].distance = 0;

    int queueIndex = 1;
    for (int i = 0; i < graph->numVertices; i++) {
        // Extract the vertex with the minimum distance from the priority queue
        int minIndex = 0;
        for (int j = 1; j < queueIndex; j++) {
            if (priorityQueue[j].distance < priorityQueue[minIndex].distance) {
                minIndex = j;
            }
        }
        priorityQueue[queueIndex - 1].distance = priorityQueue[minIndex].distance;
        queueIndex++;

        // Update distances of adjacent vertices
        for (int j = 0; j < graph->numVertices; j++) {
            if (graph->adjList[priorityQueue[minIndex].vertex][j] != INT_MAX && priorityQueue[minIndex].distance + graph->adjList[priorityQueue[minIndex].vertex][j] < distance[j]) {
                distance[j] = priorityQueue[minIndex].distance + graph->adjList[priorityQueue[minIndex].vertex][j];
                priorityQueue[queueIndex - 1].vertex = j;
                priorityQueue[queueIndex - 1].distance = distance[j];
                queueIndex++;
            }
        }

        // Mark the extracted vertex as visited
        visited[priorityQueue[minIndex].vertex] = 1;
    }

    // Print the shortest distances
    printf("Vertex\tDistance\n");
    for (int i = 0; i < graph->numVertices; i++) {
        printf("%d\t%d\n", i, distance[i]);
    }

    // Free allocated memory
    free(distance);
    free(visited);
    free(priorityQueue);
    for (int i = 0; i < graph->numVertices; i++) {
        free(graph->adjList[i]);
    }
    free(graph->adjList);
    free(graph);
}

int main() {
    // Create a graph
    Graph* graph = createGraph(5);
    addEdge(graph, 0, 1, 4);
    addEdge(graph, 0, 2, 1);
    addEdge(graph, 1, 3, 1);
    addEdge(graph, 2, 1, 2);
    addEdge(graph, 2, 3, 5);
    addEdge(graph, 3, 4, 3);

    // Find the shortest path from the source node
    dijkstra(graph, 0);

