        for (int i = 0; i < s.length(); i++) {
            buildSuffixTree(s, i, root);
        }
    }

    void buildSuffixTree(string s, int index, Node* node) {
        Node* newNode = new Node(s[index], node->depth + 1, s.substr(index));
        node->children.push_back(newNode);
        if (index + 1 < s.length()) {
            buildSuffixTree(s, index + 1, newNode);
        }
    }

    string longestRepeatedSubstring(string s) {
        set<string> repeatedSubstrings;
        buildRepeatedSubstrings(s, root, repeatedSubstrings);
        string longestSubstring = "";
        for (auto& substring : repeatedSubstrings) {
            if (substring.length() > longestSubstring.length()) {
                longestSubstring = substring;
            }
        }
        return longestSubstring;
    }

    void buildRepeatedSubstrings(string s, Node* node, set<string>& repeatedSubstrings) {
        if (node->children.empty()) {
            repeatedSubstrings.insert(node->substring);
            return;
        }
        for (auto& child : node->children) {
            buildRepeatedSubstrings(s, child, repeatedSubstrings);
