public class Main {
    public static String compressData(String input) {
        Map<Character, Integer> frequencyMap = new HashMap<>();
        for (char c : input.toCharArray()) {
            frequencyMap.put(c, frequencyMap.getOrDefault(c, 0) + 1);
        }

        PriorityQueue<Node> priorityQueue = new PriorityQueue<>();
        for (Map.Entry<Character, Integer> entry : frequencyMap.entrySet()) {
            priorityQueue.add(new Node(entry.getKey(), entry.getValue()));
        }

        while (priorityQueue.size() > 1) {
            Node node1 = priorityQueue.poll();
            Node node2 = priorityQueue.poll();

            Node newNode = new Node('\0', node1.frequency + node2.frequency);
            newNode.left = node1;
            newNode.right = node2;

            priorityQueue.add(newNode);
        }

        Node root = priorityQueue.poll();

        StringBuilder compressed = new StringBuilder();
        for (char c : input.toCharArray()) {
            int code = 0;
            Node currentNode = root;
            while (currentNode != null) {
                if (c == currentNode.character) {
                    break;
                }
                if (c < currentNode.character) {
                    code = code * 2 + 0;
                    currentNode = currentNode.left;
                } else {
                    code = code * 2 + 1;
                    currentNode = currentNode.right;
                }
            }
            compressed.append(code);
        }

        return compressed.toString();
    }

    public static void main(String[] args) {
        String input = "this is an example for huffman encoding";
        System.out.println(compressData(input));
    }
