#[derive(PartialEq, Eq, Clone, Debug)]
pub struct ListNode {
    pub val: i32,
    pub next: Option<Box<ListNode>>,
}

impl ListNode {
    #[inline]
    fn new(val: i32) -> Self {
        ListNode {
            next: None,
            val,
        }
    }
}

pub struct Solution;

impl Solution {
    pub fn merge_sort_list(head: Option<Box<ListNode>>) -> Option<Box<ListNode>> {
        if head.is_none() {
            return None;
        }

        let mut head = head.unwrap();
        let mut mid = self.get_middle(head);
        let mut right = self.get_next_half(mid);

        let mut sorted_left = Solution::merge_sort_list(head);
        let mut sorted_right = Solution::merge_sort_list(right);

        let mut sorted_head = Solution::merge(&sorted_left, &sorted_right);

        sorted_head
    }

    fn get_middle(head: Option<Box<ListNode>>) -> Option<Box<ListNode>> {
        let mut slow = head;
        let mut fast = head;

        while fast.next.is_some() && fast.next.as_ref().unwrap().next.is_some() {
            slow = slow.next.as_ref().unwrap();
            fast = fast.next.as_ref().unwrap().next;
        }

        slow.next = None;
        slow
    }

    fn get_next_half(head: Option<Box<ListNode>>) -> Option<Box<ListNode>> {
        let mut next_half = head;
        let mut slow = head;

        while slow.next.is_some() {
            next_half = next_half.next.as_ref().unwrap();
            slow = slow.next.as_ref().unwrap();
        }

        next_half.next
    }

    fn merge(head1: Option<Box<ListNode>>, head2: Option<Box<ListNode>>) -> Option<Box<ListNode>> {
        let mut dummy = Box::new(ListNode::new(0));
        let mut current = dummy;

        while let Some(node1) = head1.as_ref() {
            let node2 = head2.as_ref();

            if node1.val <= node2.val {
                current.next = node1;
                head1 = node1.next;
            } else {
                current.next = node2;
                head2 = node2.next;
            }

            current = current.next;
        }

        if head1.is_some() {
            current.next = head1;
        } else {
            current.next = head2;
        }

        dummy.next
    }
}
