void bfs(int* dist, int* parent, int** graph, int source, int sink) {
    int n = graph ? graph[0] ? graph[0][0].size : 0 : 0;
    for (int i = 0; i < n; i++) {
        dist[i] = INF;
    }
    dist[source] = 0;

    int queue[n];
    int front = 0, rear = 0;
    queue[rear++] = source;

    while (front < rear) {
        int u = queue[front++];
        for (int v = 0; v < n; v++) {
            if (graph[u][v].capacity > 0 && dist[v] > dist[u] + graph[u][v].cost) {
                dist[v] = dist[u] + graph[u][v].cost;
                parent[v] = u;
                if (v == sink) {
                    return;
                }
                queue[rear++] = v;
            }
        }
    }
}

int find_max_flow(int** graph, int source, int sink) {
    int n = graph ? graph[0] ? graph[0][0].size : 0 : 0;
    int max_flow = 0;

    int* dist = (int*)malloc(n * sizeof(int));
    int* parent = (int*)malloc(n * sizeof(int));
    int** residual_graph = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        residual_graph[i] = (int*)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            residual_graph[i][j] = (int*)malloc(1 + graph[i][j].capacity * sizeof(int));
            for (int k = 0; k <= graph[i][j].capacity; k++) {
                residual_graph[i][j][k] = graph[i][j].capacity - k;
            }
        }
    }

    while (bfs(dist, parent, graph, source, sink)) {
        int path_flow = INF;
        int s = sink;
        while (s != source) {
            int u = parent[s];
            int capacity = graph[u][s].capacity;
            int cost = graph[u][s].cost;
            int flow = residual_graph[u][s][capacity];
            path_flow = Math.Min(path_flow, flow);
            s = u;
        }
        max_flow += path_flow;

        int v = sink;
        while (v != source) {
            int u = parent[v];
            int capacity = graph[u][v].capacity;
            int cost = graph[u][v].cost;
            residual_graph[u][v][capacity] -= path_flow;
            residual_graph[v][u][capacity + path_flow] = 0;
            v = u;
        }
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            free(residual_graph[i][j]);
        }
        free(residual_graph[i]);
    }
    free(parent);
    free(dist);
    free(residual_graph);

    return max_flow;
}
