    }

    for _ in 0..N {
        let mut a = rand::thread_rng().gen_range(2, num);
        a = a.wrapping_mul(d).wrapping_add(1);

        if a == 1 || a == num - 1 {
            continue;
        }

        let mut x = a;
        while x != num - 1 && x != 1 {
            x = x.wrapping_mul(d);
        }

        if x != num - 1 {
            return false;
        }
    }

    true
}

fn main() {
    println!("{}", is_prime_miller_rabin(25));  // false
    println!("{}", is_prime_miller_rabin(23));  // true
    println!("{}", is_prime_miller_rabin(37));  // true
    println!("{}", is_prime_miller_rabin(48));  // false
}
